import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import EmployeeLayout from '../components/EmployeeLayout';
import layout2Styles from '../styles/layout2.module.css';
// import sharedStyles from './PageStyle2.module.css';
// import styles from '../styles/bookCards.module.css';
import bookCardsStyle from '../styles/bookCards.module.css';

function EditBookPage() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [formData, setFormData] = useState({
    seriesTitle: '',
    seriesStartDate: '',
    seriesEndDate: '',
    publisher: '',
    issueNumber: '',
    releaseDate: '',
    coverArt: '',
  });
  const [tags, setTags] = useState([]);
  const [currentTag, setCurrentTag] = useState('');
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');

  const formatDateForInput = (dateString) => {
    if (!dateString) return '';
    return new Date(dateString).toISOString().split('T')[0];
  };

  useEffect(() => {
    const fetchBook = async () => {
      try {
        const userInfo = JSON.parse(localStorage.getItem('userInfo'));
        const config = {
          headers: {
            Authorization: `Bearer ${userInfo.token}`,
          },
        };
        const { data } = await axios.get(`/api/books/${id}`, config);
        setFormData({
          seriesTitle: data.seriesTitle,
          seriesStartDate: formatDateForInput(data.seriesStartDate),
          seriesEndDate: formatDateForInput(data.seriesEndDate),
          publisher: data.publisher,
          issueNumber: data.issueNumber,
          releaseDate: formatDateForInput(data.releaseDate),
          coverArt: data.coverArt || '',
        });
        setTags(data.tags || []);
      } catch (err) {
        setError('Could not fetch book data.');
      }
    };
    fetchBook();
  }, [id]);



  const onChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleAddTag = () => {
    if (currentTag && !tags.includes(currentTag)) {
      setTags([...tags, currentTag]);
      setCurrentTag('');
    }
  };

  const handleRemoveTag = (tagToRemove) => {
    setTags(tags.filter(tag => tag !== tagToRemove));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setMessage('');

    try {
      const userInfo = JSON.parse(localStorage.getItem('userInfo'));
      const config = {
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${userInfo.token}`,
        },
      };

      const bookData = { ...formData, tags, seriesEndDate: formData.seriesEndDate || null };    




      await axios.put(`/api/books/${id}`, bookData, config);
      setMessage('Book updated successfully!');

      } catch (err) {
      setError(err.response?.data?.message || 'An error occurred during update.');
    }
  };

  const handleDelete = async () => {
    if (window.confirm('Are you sure you want to permanently delete this book? This action cannot be undone.')) {
      try {
        const userInfo = JSON.parse(localStorage.getItem('userInfo'));
        const config = {
          headers: {
            Authorization: `Bearer ${userInfo.token}`,
          },
        };
        await axios.delete(`/api/books/${id}`, config);
        navigate('/inventory');
      } catch (err) {
        setError(err.response?.data?.message || 'Could not delete book.');
      }
    }
  };

  return (
    <EmployeeLayout title={`Edit: ${formData.seriesTitle || 'Book'}`}>
      {message && <p style={{ color: 'green', textAlign: 'center' }}>{message}</p>}
      {error && <p className={layout2Styles.error}>{error}</p>}
      <div className={bookCardsStyle.editContainer}>
        <div className={bookCardsStyle.coverArtSection}>
          <img src={formData.coverArt || '/images/cover-placeholder.png'} alt="Cover Art" />
        </div>
        <div className={bookCardsStyle.formContent}>
          <form onSubmit={handleSubmit}>
            <div className={bookCardsStyle.formGrid}>
              <div className={bookCardsStyle.formGroup}>
              <label htmlFor="seriesTitle">Series Title*:</label>
              <input id="seriesTitle" type="text" name="seriesTitle" value={formData.seriesTitle} onChange={onChange} required />
              </div>
              <div className={bookCardsStyle.formGroup}>
              <label htmlFor="issueNumber">Issue Number*:</label>
              <input id="issueNumber" type="number" name="issueNumber" value={formData.issueNumber} onChange={onChange} required />
              </div>
              <div className={bookCardsStyle.formGroup}>
              <label htmlFor="publisher">Publisher*:</label>
              <input id="publisher" type="text" name="publisher" value={formData.publisher} onChange={onChange} required />
              </div>
              <div className={bookCardsStyle.formGroup}>
              <label htmlFor="releaseDate">Release Date*:</label>
              <input id="releaseDate" type="date" name="releaseDate" value={formData.releaseDate} onChange={onChange} required />
              </div>
              <div className={bookCardsStyle.formGroup}>
              <label htmlFor="seriesStartDate">Series Start Date*:</label>
              <input id="seriesStartDate" type="date" name="seriesStartDate" value={formData.seriesStartDate} onChange={onChange} required />
              </div>
              <div className={bookCardsStyle.formGroup}>
              <label htmlFor="seriesEndDate">Series End Date:</label>
              <input id="seriesEndDate" type="date" name="seriesEndDate" value={formData.seriesEndDate} onChange={onChange} />
              </div>
            </div>

            <div className={bookCardsStyle.tagsSection}>
              <div className={bookCardsStyle.formGroup}>
                <label htmlFor="tag-input">Tags:</label>
                <div className={bookCardsStyle.tagInputContainer}>
                  <input
                    id="tag-input"
                    type="text"
                    value={currentTag}
                    onChange={(e) => setCurrentTag(e.target.value)}
                    onKeyDown={(e) => { if (e.key === 'Enter') { e.preventDefault(); handleAddTag(); } }}
                  />
                  <button type="button" onClick={handleAddTag} className={layout2Styles.menuItem} style={{ backgroundColor: '#004085', color: 'white', padding: '0.5rem 1rem' }}>Add Tag</button>
                </div>
                <div className={bookCardsStyle.tagsDisplay}>
                  {tags.map(tag => (
                    <span key={tag} className={bookCardsStyle.tag}>
                      {tag}
                      <button type="button" onClick={() => handleRemoveTag(tag)} className={bookCardsStyle.removeTagBtn}>x</button>
                    </span>
                  ))}
                </div>
              </div>
            </div>

            <div className={bookCardsStyle.formActions}>
              <button type="button" onClick={handleDelete} className={layout2Styles.logoutButton}>Delete</button>
              <button type="button" onClick={() => navigate('/inventory')} className={layout2Styles.menuItem} style={{ backgroundColor: '#6c757d', color: 'white' }}>Cancel</button>
              <button type="submit" className={layout2Styles.menuItem} style={{ backgroundColor: '#004085', color: 'white' }}>Save Changes</button>
            </div>
          </form>
        </div>
      </div>
    </EmployeeLayout>
  );
}

export default EditBookPage;
